/** Flatten nested keys for type-safe access: "common.save", "auth.login", etc. */
export type TranslationKey = {
  [NS in keyof TranslationDictionary]: `${NS}.${string & keyof TranslationDictionary[NS]}`;
}[keyof TranslationDictionary];

export interface TranslationOptions {
  locale?: Locale;
  fallbackLocale?: Locale;
  interpolation?: Record<string, string | number>;
  count?: number;
}

export interface LocaleConfig {
  locale: Locale;
  name: string;
  shortName: string;
  direction: 'ltr' | 'rtl';
  dateFormat: string;
  numberFormat: { decimal: string; thousands: string };
}

export interface I18nConfig {
  defaultLocale: Locale;
  supportedLocales: Locale[];
  fallbackLocale: Locale;
}

