export const dictionaries: Record<Locale, TranslationDictionary> = {
  'pt-BR': ptBR,
  en,
  es,
};

// ─────────────────────────────────────────────
// PURE FUNCTIONS
// ─────────────────────────────────────────────

/**
 * Splits a full translation key into namespace and key parts.
 * @example resolveNamespaceAndKey('common.save') → { namespace: 'common', key: 'save' }
 */
export function resolveNamespaceAndKey(fullKey: TranslationKey): {
  namespace: TranslationNamespace;
  key: string;
} {
  const dotIndex = fullKey.indexOf('.');
  const namespace = fullKey.slice(0, dotIndex) as TranslationNamespace;
  const key = fullKey.slice(dotIndex + 1);
  return { namespace, key };
}

/**
 * Replaces `{{key}}` placeholders with values from the provided record.
 * Unmatched placeholders are left as-is.
 */
export function interpolate(
  template: string,
  values: Record<string, string | number>,
): string {
  return template.replace(/\{\{(\w+)\}\}/g, (match, placeholder: string) => {
    if (placeholder in values) {
      return String(values[placeholder]);
    }
    return match;
  });
}

/**
 * Retrieves a translation string for the given key and locale.
 * Falls back to the fallback locale, then returns the key itself if not found.
 * Supports interpolation via options.interpolation.
 */
export function getTranslation(
  key: TranslationKey,
  locale: Locale,
  options?: TranslationOptions,
): string {
  const { namespace, key: fieldKey } = resolveNamespaceAndKey(key);
  const fallback = options?.fallbackLocale ?? FALLBACK_LOCALE;

  const dict = dictionaries[locale];
  const ns = dict?.[namespace] as Record<string, string> | undefined;
  let value = ns?.[fieldKey];

  // Fallback to fallback locale if empty or missing
  if (!value && locale !== fallback) {
    const fallbackDict = dictionaries[fallback];
    const fallbackNs = fallbackDict?.[namespace] as Record<string, string> | undefined;
    value = fallbackNs?.[fieldKey];
  }

  // If still not found, return the key itself
  if (!value) {
    return key;
  }

  // Apply interpolation if provided
  if (options?.interpolation) {
    return interpolate(value, options.interpolation);
  }

  return value;
}

/**
 * Type guard: checks whether a string is a valid Locale.
 */
export function isValidLocale(value: string): value is Locale {
  return SUPPORTED_LOCALES.includes(value as Locale);
}

/**
 * Returns the full config for a given locale.
 */
export function getLocaleConfig(locale: Locale): LocaleConfig {
  return LOCALE_CONFIGS[locale];
}

/**
 * Returns configs for all supported locales.
 */
export function getSupportedLocales(): LocaleConfig[] {
  return SUPPORTED_LOCALES.map((l) => LOCALE_CONFIGS[l]);
}

/**
 * Detects the preferred locale from multiple sources.
 * Priority: URL param > cookie > browser languages > Accept-Language header > default.
 */
export function detectLocale(sources: {
  url?: string;
  cookie?: string;
  browserLanguages?: readonly string[];
  header?: string;
}): Locale {
  // 1. URL param (?lang=en or ?locale=es)
  if (sources.url) {
    try {
      const searchParams = new URL(sources.url, 'http://localhost').searchParams;
      const langParam = searchParams.get('lang') ?? searchParams.get('locale');
      if (langParam && isValidLocale(langParam)) {
        return langParam;
      }
    } catch {
      // Invalid URL, skip
    }
  }

  // 2. Cookie (locale=pt-BR)
  if (sources.cookie) {
    const match = sources.cookie.match(/(?:^|;\s*)locale=([^;]+)/);
    if (match) {
      const cookieLocale = match[1].trim();
      if (isValidLocale(cookieLocale)) {
        return cookieLocale;
      }
    }
  }

  // 3. Browser languages (navigator.languages)
  if (sources.browserLanguages && sources.browserLanguages.length > 0) {
    for (const lang of sources.browserLanguages) {
      if (isValidLocale(lang)) {
        return lang;
      }
      // Try matching prefix: "pt" → "pt-BR", "en-US" → "en"
      const prefix = lang.split('-')[0].toLowerCase();
      const found = SUPPORTED_LOCALES.find(
        (supported) => supported.toLowerCase().startsWith(prefix),
      );
      if (found) {
        return found;
      }
    }
  }

  // 4. Accept-Language header
  if (sources.header) {
    const parts = sources.header
      .split(',')
      .map((part) => {
        const [tag, qPart] = part.trim().split(';');
        const q = qPart ? parseFloat(qPart.replace('q=', '')) : 1;
        return { tag: tag.trim(), q };
      })
      .sort((a, b) => b.q - a.q);

    for (const { tag } of parts) {
      if (isValidLocale(tag)) {
        return tag;
      }
      const prefix = tag.split('-')[0].toLowerCase();
      const found = SUPPORTED_LOCALES.find(
        (supported) => supported.toLowerCase().startsWith(prefix),
      );
      if (found) {
        return found;
      }
    }
  }

  return DEFAULT_LOCALE;
}

/**
 * Formats a Date according to the locale's date format pattern.
 */
export function formatDate(date: Date, locale: Locale): string {
  const config = LOCALE_CONFIGS[locale];
  const day = String(date.getDate()).padStart(2, '0');
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const year = String(date.getFullYear());

  switch (config.dateFormat) {
    case 'MM/DD/YYYY':
      return `${month}/${day}/${year}`;
    case 'DD/MM/YYYY':
    default:
      return `${day}/${month}/${year}`;
  }
}

/**
 * Formats a number according to the locale's number format config.
 */
export function formatNumber(
  value: number,
  locale: Locale,
  decimals?: number,
): string {
  const config = LOCALE_CONFIGS[locale];
  const fixedDecimals = decimals ?? 0;
  const abs = Math.abs(value);
  const sign = value < 0 ? '-' : '';

  const parts = abs.toFixed(fixedDecimals).split('.');
  const integerPart = parts[0];
  const decimalPart = parts[1];

  // Add thousands separators
  const withThousands = integerPart.replace(
    /\B(?=(\d{3})+(?!\d))/g,
    config.numberFormat.thousands,
  );

  if (fixedDecimals > 0 && decimalPart) {
    return `${sign}${withThousands}${config.numberFormat.decimal}${decimalPart}`;
  }

  return `${sign}${withThousands}`;
}

/**
 * Returns all translation keys, optionally filtered by namespace.
 */
export function getAllKeys(namespace?: TranslationNamespace): TranslationKey[] {
  const dict = dictionaries[DEFAULT_LOCALE];
  const namespaces = namespace ? [namespace] : (Object.keys(dict) as TranslationNamespace[]);

  const keys: TranslationKey[] = [];
  for (const ns of namespaces) {
    const nsDict = dict[ns] as Record<string, string>;
    for (const key of Object.keys(nsDict)) {
      keys.push(`${ns}.${key}` as TranslationKey);
    }
  }

  return keys;
}

/**
 * Returns translation keys that have empty string values for a given locale.
 * Useful for auditing completeness of translations.
 */
export function getMissingTranslations(locale: Locale): TranslationKey[] {
  const dict = dictionaries[locale];
  const missing: TranslationKey[] = [];

  for (const ns of Object.keys(dict) as TranslationNamespace[]) {
    const nsDict = dict[ns] as Record<string, string>;
    for (const [key, value] of Object.entries(nsDict)) {
      if (value === '') {
        missing.push(`${ns}.${key}` as TranslationKey);
      }
    }
  }

  return missing;
}

// ─────────────────────────────────────────────
// REACT HOOK (client-only)
// ─────────────────────────────────────────────

/**
 * Helper to safely read a cookie value in browser environments.
 * Returns undefined in Node.js / SSR.
 */
function getCookieValue(name: string): string | undefined {
  try {
    if (typeof document === 'undefined') return undefined;
    const match = document.cookie.match(new RegExp(`(?:^|;\\s*)${name}=([^;]+)`));
    return match?.[1];
  } catch {
    return undefined;
  }
}

/**
 * Helper to set a cookie in browser environments.
 */
function setCookieValue(name: string, value: string, days: number): void {
  try {
    if (typeof document === 'undefined') return;
    const expires = new Date(Date.now() + days * 864e5).toUTCString();
    document.cookie = `${name}=${value}; expires=${expires}; path=/; SameSite=Lax`;
  } catch {
    // SSR or restricted environment — silently skip
  }
}

/**
 * Detects the initial locale in browser context.
 */
function detectBrowserLocale(): Locale {
  try {
    if (typeof window === 'undefined') return DEFAULT_LOCALE;

    return detectLocale({
      url: window.location.href,
      cookie: document.cookie,
      browserLanguages: navigator.languages,
    });
  } catch {
    return DEFAULT_LOCALE;
  }
}

export interface UseTranslationReturn {
  t: (key: TranslationKey, options?: TranslationOptions) => string;
  locale: Locale;
  setLocale: (locale: Locale) => void;
  locales: LocaleConfig[];
}

/**
 * React hook for translations.
 *
 * **Must only be used in client components** ('use client').
 *
 * @param namespace - Optional namespace to scope translations (not currently
 *   used to filter, but reserved for future optimisation).
 */
export function useTranslation(
  _namespace?: TranslationNamespace,
): UseTranslationReturn {
  const [locale, setLocaleState] = useState<Locale>(() => {
    // Try to read persisted locale from cookie first
    const cookieLocale = getCookieValue('locale');
    if (cookieLocale && isValidLocale(cookieLocale)) {
      return cookieLocale;
    }
    return detectBrowserLocale();
  });

  // Sync locale from browser on mount (handles SSR hydration mismatch)
  useEffect(() => {
    const detected = detectBrowserLocale();
    const cookieLocale = getCookieValue('locale');
    // Prefer persisted cookie over auto-detection
    if (cookieLocale && isValidLocale(cookieLocale)) {
      setLocaleState(cookieLocale);
    } else if (detected !== locale) {
      setLocaleState(detected);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const setLocale = useCallback((newLocale: Locale) => {
    setLocaleState(newLocale);
    setCookieValue('locale', newLocale, 365);
  }, []);

  const t = useCallback(
    (key: TranslationKey, options?: TranslationOptions) => {
      const effectiveLocale = options?.locale ?? locale;
      return getTranslation(key, effectiveLocale, options);
    },
    [locale],
  );

  const locales = getSupportedLocales();

  return { t, locale, setLocale, locales };
}
